input.command:
# Load the GitHub results from the temp file
$githubResults = Get-Content "$env:TEMP\github-skills.json" | ConvertFrom-Json

# Skills comparison data
$skillMappings = @(
  @{local="algorithmic-art"; github="algorithmic-art"; localLines=404}
  @{local="canvas-design"; github="canvas-design"; localLines=129}
  @{local="frontend-design"; github="frontend-design"; localLines=42}
  @{local="theme-factory"; github="theme-factory"; localLines=59}
  @{local="slack-gif-creator"; github="slack-gif-creator"; localLines=254}
  @{local="docx"; github="docx"; localLines=590}
  @{local="pdf"; github="pdf"; localLines=314}
  @{local="pptx"; github="pptx"; localLines=232}
  @{local="xlsx"; github="xlsx"; localLines=291}
  @{local="claude-api"; github="claude-api"; localLines=325}
  @{local="mcp-builder"; github="mcp-builder"; localLines=236}
  @{local="web-artifacts-builder"; github="web-artifacts-builder"; localLines=73}
  @{local="webapp-testing"; github="webapp-testing"; localLines=95}
  @{local="brand-guidelines"; github="brand-guidelines"; localLines=73}
  @{local="doc-coauthoring"; github="doc-coauthoring"; localLines=375}
  @{local="internal-comms"; github="internal-comms"; localLines=32}
  @{local="skill-creator"; github="skill-creator"; localLines=485}
)

$comparison = @()

foreach ($mapping in $skillMappings) {
  $skillKey = $mapping.github
  $skillObj = $githubResults.$skillKey

  if ($skillObj.success) {
    $githubLines = $skillObj.lineCount
    $localLines = $mapping.localLines
    $identical = ($githubLines -eq $localLines)

    $comparison += [PSCustomObject]@{
      Skill = $mapping.local
      LocalLines = $localLines
      GitHubLines = $githubLines
      Identical = $identical
      Difference = $githubLines - $localLines
    }
  }
}

# Display comparison
$comparison | Format-Table Skill, LocalLines, GitHubLines, Identical, Difference -AutoSize

# Summary
$identicalCount = ($comparison | Where-Object {$_.Identical -eq $true}).Count
$differentCount = $comparison.Count - $identicalCount
Write-Host "`nSummary: $identicalCount identical, $differentCount different"
